package com.example.sharetarget;

import android.app.Activity;
import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.text.TextUtils;
import android.widget.ImageView;
import android.widget.LinearLayout;
import android.widget.ScrollView;
import android.widget.TextView;

public class ShareReceiverActivity extends Activity {

    private TextView textView;
    private ImageView imageView;
    private TextView uriView;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        ScrollView scrollView = new ScrollView(this);
        LinearLayout root = new LinearLayout(this);
        root.setOrientation(LinearLayout.VERTICAL);
        int pad = dp(16);
        root.setPadding(pad, pad, pad, pad);

        textView = new TextView(this);
        imageView = new ImageView(this);
        uriView = new TextView(this);

        imageView.setAdjustViewBounds(true);
        imageView.setMaxWidth(getResources().getDisplayMetrics().widthPixels - (pad * 2));

        root.addView(textView);
        root.addView(imageView);
        root.addView(uriView);
        scrollView.addView(root);
        setContentView(scrollView);

        handleShareIntent(getIntent());
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent);
        handleShareIntent(intent);
    }

    private void handleShareIntent(Intent intent) {
        if (intent == null) {
            showText("No shared content.");
            return;
        }

        String action = intent.getAction();
        String type = intent.getType();

        if (Intent.ACTION_SEND.equals(action)) {
            if (type != null && type.startsWith("image/")) {
                Uri imageUri = intent.getParcelableExtra(Intent.EXTRA_STREAM);
                if (imageUri != null) {
                    imageView.setImageURI(imageUri);
                    imageView.setVisibility(android.view.View.VISIBLE);
                    textView.setText("");
                    uriView.setText("Shared image URI: " + imageUri.toString());
                } else {
                    showText("Shared image, but no URI was provided.");
                }
            } else if ("text/plain".equals(type) || type == null) {
                CharSequence sharedText = intent.getCharSequenceExtra(Intent.EXTRA_TEXT);
                String sharedSubject = intent.getStringExtra(Intent.EXTRA_SUBJECT);

                StringBuilder sb = new StringBuilder();
                if (!TextUtils.isEmpty(sharedSubject)) {
                    sb.append("Subject: ").append(sharedSubject).append("\n\n");
                }
                if (!TextUtils.isEmpty(sharedText)) {
                    sb.append(sharedText);
                }
                if (sb.length() == 0) {
                    sb.append("No shared text found.");
                }
                showText(sb.toString());
            } else {
                showText("Unsupported shared content type: " + type);
            }
        } else if (Intent.ACTION_VIEW.equals(action)) {
            Uri data = intent.getData();
            if (data != null) {
                showText("Opened via VIEW intent:");
                uriView.setText(data.toString());
            } else {
                showText("No content provided.");
            }
        } else {
            showText("Unsupported action: " + action);
        }
    }

    private void showText(String text) {
        textView.setVisibility(android.view.View.VISIBLE);
        imageView.setVisibility(android.view.View.GONE);
        textView.setText(text);
        uriView.setText("");
    }

    private int dp(int value) {
        float density = getResources().getDisplayMetrics().density;
        return (int) (value * density + 0.5f);
    }
}

